#include<bits/stdc++.h>
using namespace std;
vector<double> a[1010];
double ans[1010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        a[i].push_back(0);
        for(int j=1;j<=n+1;j++)
        {
            double x;
            scanf("%lf",&x);
            a[i].push_back(x);
        }
    }
    for(int i=1;i<=n;i++)
    {
        int max2=i;
        for(int j=i+1;j<=n;j++)
        {
            if(abs(a[i][j])>abs(a[i][max2]))
            {
                max2=j;
            }
        }
        if(abs(a[i][max2])<1e-9)
        {
            printf("No Solution");
            return 0;
        }
        if(max2!=i)
        {
            swap(a[i],a[max2]);
        }
        for(int j=n+1;j>=i;j--)
        {
            a[i][j]/=a[i][i];
        }
        for(int j=i+1;j<=n;j++)
        {
            for(int k=n+1;k>=i;k--)
            {
                a[j][k]-=a[j][i]*a[i][k];
            }
        }
    }
    for(int i=n;i>=1;i--)
    {
        for(int j=i+1;j<=n;j++)
        {
            a[i][n+1]-=a[j][n+1]*a[i][j];
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%.2lf\n",a[i][n+1]);
    }
    return 0;
}
